func (f WebServerConfigService) Update(servername string, config []byte) error {
	global.GVA_LOG = log.ZapLogger() // Е┬²Е╖▀Е▄√zapФ≈╔Е©≈Е╨⌠
	mainCtx, err := local.JsonLoader(config).Load()
	if err != nil {
		return err
	}
	lines, err := mainCtx.ConfigLines(false)
	if err != nil {
		return err
	}
	global.GVA_LOG.Info(strings.Join(lines, "\n"))
	return nil
}

